var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"헉 헉…","JPN":"はあ、はあ……","ENG":"*Huff* *Huff*","TWN":"呼…咳咳…"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"더는… 못 버티겠어…","JPN":"もう……これ以上は無理……","ENG":"I can't... go on anymore...","TWN":"我已經…撐不住了…"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"나 이렇게… 죽는 거야…?","JPN":"こんなふうに……私は死んでしまうの……？","ENG":"Is this... how I'll die...?","TWN":"我就要這樣…死了嗎…？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"괜찮은가. 소녀여.","JPN":"大丈夫か、少女よ。","ENG":"Are you all right, girl?","TWN":"…你沒事吧，孩子。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"당신은…?","JPN":"あなたは……？","ENG":"You are...?","TWN":"你是…？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"난민들을 마물로부터 홀로 지켰다고 들었다.","JPN":"難民たちを魔物からたった一人で守ったくれたと聞いた。","ENG":"I heard that you had protected the refugees from the monsters all by yourself.","TWN":"聽說你獨自從怪物爪下守護了那些難民。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"아직 어린 나이에도 용감하구나.","JPN":"まだ幼い子どもなのに、勇敢であるな。","ENG":"For someone as young as you, I admire your courage.","TWN":"小小年紀卻如此勇敢。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"전 최선을 다했다고 생각했는데…","JPN":"私は力の限りを尽くしたけど……","ENG":"I thought I was just doing my best...","TWN":"我覺得我已經盡力了…"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"아이를 지키려던 엄마가… 마물에게 죽었어요.","JPN":"子どもを庇おうとした母親が……魔物に殺されました。","ENG":"But the monsters... got the mother who was protecting her child.","TWN":"那個想要保護孩子的母親…被怪物殺死了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"제가 좀 더 강한 사람이었으면, 그 사람을 구할 수 있었겠죠.","JPN":"私がもっと強かったら、あの母親も助けることができたんでしょう。","ENG":"If only I was a bit stronger, I could've saved her too.","TWN":"如果我再強一點，或許能救下她…"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"자책하지 말아라.","JPN":"自分を責めるな。","ENG":"Do not blame yourself.","TWN":"不要自責。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_CA_QM","text":{"KOREA":"네가 나서지 않았다면 수많은 난민들이 희생되었을 것이다.","JPN":"そなたがいてくれなかったら、多くの難民が犠牲になっていたところだ。","ENG":"If you had not stepped forward, many refugees would have lost their lives.","TWN":"如果不是你挺身而出，會有更多難民死去。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"나의 이름은 에클레시아.","JPN":"我の名はエクレシア。","ENG":"My name is Ecclesia.","TWN":"我的名字艾可露西亞。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"네 이름은 무엇이냐?","JPN":"そなたの名は？","ENG":"What is yours?","TWN":"你叫什麼名字？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"이름은…  없어요.","JPN":"名前は、ありません。","ENG":"I don't... have a name.","TWN":"我沒有…名字。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"저는 이름을 가지면 안 된다고 그랬거든요.","JPN":"私は名前を持ってはいけないそうです。","ENG":"I was told that I shouldn't be given one.","TWN":"他們說我不能有名字。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"가족은 어디에 있지? 돌아갈 곳은 있느냐?","JPN":"家族はどこにいる？　帰る場所はあるのか？","ENG":"Where is your family? Do you have a place to return to?","TWN":"你的家人在哪裡？有地方可以回去嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"없어요.","JPN":"いいえ。","ENG":"No.","TWN":"沒有了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"어머니랑 둘이서 살았는데, 얼마 전에 역병으로 돌아가셨어요.","JPN":"お母さんと二人で暮らしていたんですが、少し前に疫病に罹り亡くなりました。","ENG":"I used to live with my mom, but she died from the plague recently.","TWN":"我和媽媽一起生活，但她前不久因為瘟疫去世了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"POOR_ROOT_NPC_NULL","text":{"KOREA":"역병 환자가 있던 집은 남겨두면 안 된다면서… 어른들이 다 불태웠고요.","JPN":"疫病患者の家は残しておけないと……大人たちに家は燃やされてしまいました。","ENG":"And the adults... burned down my house, saying that they can't let a house of a plague patient remain.","TWN":"大人說不能留下有瘟疫患者的房子…所以全都燒了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…그런가.","JPN":"……そうであったか。","ENG":"…I see.","TWN":"是嗎…？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"내가 너에게 머물 곳을 마련해주마.","JPN":"我がそなたに住む場所を与えよう。","ENG":"Then I shall put a roof over your head.","TWN":"我會為你安排一個住處。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"대신, 하나 제안을 하고 싶구나.","JPN":"その代わり一つ提案させてほしい。","ENG":"In return, I would like to propose an offer.","TWN":"不過，我想再提一個提議。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};